import type { KeyboardEvent, ReactEventHandler, ReactNode } from 'react';

import { actionButton } from './actions.sty.js';
import { Button } from '../../../../../../buttons/button/Button.js';
import { useTooltipReducer } from '../../useTooltipReducer.js';

/**
 * Props for `ChartTooltip.Action`, defining a global action item rendered in the tooltip footer.
 * @public
 */
export interface ActionProps {
  /** Label text displayed for the action */
  label: ReactNode;
  /** Optional icon displayed to the left of the label */
  icon?: ReactNode;
  /** Optional icon displayed to the right of the label */
  trailingIcon?: ReactNode;
  /** Callback executed when the action is selected */
  onSelect: ReactEventHandler;
  /** Whether the action is disabled */
  disabled?: boolean;
}

/**
 * A global tooltip action component.
 * Used as a child of OverlayTooltip to provide actions that apply to the entire tooltip content.
 * The tooltip internally manages visibility based on pinned state.
 * @public
 */
export const Action = (props: ActionProps) => {
  const { label, icon, trailingIcon, onSelect, disabled } = props;
  const dispatch = useTooltipReducer();

  const handleKeyDown = (event: KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      onSelect(event);
    }
  };

  return (
    <Button
      disabled={disabled}
      variant="default"
      className={actionButton}
      onClick={onSelect}
      onKeyDown={handleKeyDown}
      onPointerEnter={dispatch({
        type: 'SET_ACTIVE_SERIES',
        payload: { activeSeries: 'global-action' },
      })}
      width="full"
      textAlign="start"
    >
      {icon && <Button.Prefix>{icon}</Button.Prefix>}
      <Button.Label>{label}</Button.Label>
      {trailingIcon && <Button.Suffix>{trailingIcon}</Button.Suffix>}
    </Button>
  );
};
